2. SEO服务：
```typescript
@Injectable({ providedIn: 'root' })
export class SeoService {
  constructor(private meta: Meta, private title: Title) {}

  updateSeoTags(product: Product) {
    this.title.setTitle(`${product.name} - 电商平台`);
    this.meta.updateTag({ name: 'description', content: product.description });
    this.meta.updateTag({ property: 'og:title', content: product.name });
    this.meta.updateTag({ property: 'og:image', content: product.image });
    this.meta.updateTag({ property: 'og:price:amount', content: product.price.toString() });
  }
}
```

